```java
@WebMvcTest(ProductController.class)
class ProductControllerTest {
    @Autowired MockMvc mvc;
    @Autowired ObjectMapper mapper;
    @MockBean ProductService service;

    Product mouse = new Product("P001", "Mouse", 799.0, "Electronics");

    @Test
    void getAll_returns200AndList() throws Exception {
        when(service.findAll()).thenReturn(List.of(mouse));
        mvc.perform(get("/api/products"))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.length()").value(1))
            .andExpect(jsonPath("$[0].name").value("Mouse"));
    }

    @Test
    void getById_found_returns200() throws Exception {
        when(service.findByIdOrThrow("P001")).thenReturn(mouse);
        mvc.perform(get("/api/products/P001"))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.price").value(799.0));
    }

    @Test
    void getById_notFound_returns404() throws Exception {
        when(service.findByIdOrThrow("P999"))
            .thenThrow(new ResourceNotFoundException("Product", "P999"));
        mvc.perform(get("/api/products/P999")).andExpect(status().isNotFound());
    }

    @Test
    void create_validRequest_returns201() throws Exception {
        when(service.create(any())).thenReturn(mouse);
        mvc.perform(post("/api/products").contentType(APPLICATION_JSON)
                .content(mapper.writeValueAsString(
                    Map.of("name","Mouse","price",799.0,"category","Electronics","stockQty",50))))
            .andExpect(status().isCreated())
            .andExpect(jsonPath("$.id").value("P001"));
    }

    @Test
    void create_blankName_returns400WithFieldError() throws Exception {
        mvc.perform(post("/api/products").contentType(APPLICATION_JSON)
                .content(mapper.writeValueAsString(
                    Map.of("name","","price",799.0,"category","Electronics","stockQty",5))))
            .andExpect(status().isBadRequest())
            .andExpect(jsonPath("$.name").exists());
    }
}
```

```java
@DataJpaTest
@Import(ProductService.class)
class ProductServiceTest {
    @Autowired ProductRepository repo;
    @Autowired ProductService service;

    @BeforeEach
    void seed() {
        repo.save(new Product("Mouse",    799,  "Electronics"));
        repo.save(new Product("Keyboard", 1999, "Electronics"));
        repo.save(new Product("Chair",    5000, "Furniture"));
    }

    @Test
    void findByCategory_electronics_returns2() {
        assertEquals(2, repo.findByCategory("Electronics").size());
    }

    @Test
    void create_duplicate_throwsDuplicate() {
        assertThrows(DuplicateResourceException.class,
            () -> service.create(new ProductRequest("Mouse", 999.0, "Electronics", 5)));
    }

    @Test
    void findById_afterSave_returnsProduct() {
        Product saved = repo.save(new Product("Hub", 499, "Accessories"));
        assertTrue(repo.findById(saved.getId()).isPresent());
    }

    @Test
    void delete_removesProduct() {
        Product p = repo.save(new Product("Hub", 499, "Accessories"));
        service.delete(p.getId());
        assertFalse(repo.existsById(p.getId()));
    }
}
```

